'use client'

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Skeleton } from '@/components/ui/skeleton'
import { Input } from '@/components/ui/input'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Separator } from '@/components/ui/separator'
import { cn } from '@/lib/utils'

import { MoreHorizontal, Pencil, Trash } from 'lucide-react'

import { useDepartmentsList } from '../hooks/useDepartmentsList'
import { useDepartmentActions } from '../hooks/useDepartmentActions'
import { Department } from '../types/departments.types'
import { useMemo, useState } from 'react'
import { useDebounce } from '@/hooks/useDebounce'

interface DepartmentsTableProps {
  onEdit?: (department: Department) => void
}

export function DepartmentsTable({ onEdit }: DepartmentsTableProps) {
  const { departments, loading, meta, query, setQuery, refetch } = useDepartmentsList()
  const { confirmDelete, loading: isDeleting } = useDepartmentActions()

  const [search, setSearch] = useState(query.search ?? '')
  const { debouncedValue: debouncedSearch } = useDebounce(search, 350)

  // push debounced search into query
  useMemo(() => {
    setQuery((prev) => ({ ...prev, search: debouncedSearch, page: 1 }))
  }, [debouncedSearch, setQuery])

  const handlePageChange = (nextPage: number) => {
    if (!meta) return
    const safePage = Math.min(Math.max(1, nextPage), meta.totalPages)
    setQuery((prev) => ({ ...prev, page: safePage }))
  }

  const handleLimitChange = (value: string) => {
    const limit = Number(value)
    setQuery((prev) => ({ ...prev, limit, page: 1 }))
  }

  if (loading) {
    return <DepartmentsTableSkeleton />
  }

  if (!departments?.length) {
    return (
      <div className="rounded-md border p-6 text-center text-sm text-muted-foreground">
        No departments found.
      </div>
    )
  }

  return (
    <div className="space-y-3">
      <div className="flex flex-col gap-3 rounded-md border bg-gradient-to-br from-slate-50 to-white/80 p-4 shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div className="flex flex-col">
            <p className="text-xs uppercase tracking-wide text-muted-foreground">Departments</p>
            <p className="text-lg font-semibold text-slate-900">{meta?.totalDocs ?? departments.length} total</p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <Input
              placeholder="Search departments..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-56"
            />

            <Select value={String(query.limit)} onValueChange={handleLimitChange}>
              <SelectTrigger className="w-[110px]">
                <SelectValue placeholder="Rows" />
              </SelectTrigger>
              <SelectContent>
                {[5, 10, 20, 50].map((opt) => (
                  <SelectItem key={opt} value={String(opt)}>
                    {opt} / page
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Button variant="outline" size="sm" onClick={() => refetch()}>
              Refresh
            </Button>
          </div>
        </div>
      </div>

      <div className="overflow-hidden rounded-lg border bg-white shadow-sm">
        <Table>
          <TableHeader>
            <TableRow className="bg-slate-50/60">
              <TableHead>Title</TableHead>
              <TableHead>Jobs</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </TableRow>
          </TableHeader>

          <TableBody>
            {departments.map((department, idx) => (
              <TableRow
                key={department._id}
                className={cn(idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/40')}
              >
                <TableCell className="font-medium text-slate-900">
                  {department.title}
                </TableCell>

                <TableCell>
                  <Badge variant="secondary" className="font-mono text-xs">
                    {department.jobsCount ?? 0} roles
                  </Badge>
                </TableCell>

                <TableCell className="text-right">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                      >
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>

                    <DropdownMenuContent align="end">
                      <DropdownMenuItem
                        onClick={() => onEdit?.(department)}
                      >
                        <Pencil className="mr-2 h-4 w-4" />
                        Edit
                      </DropdownMenuItem>

                      <DropdownMenuItem
                        className="text-destructive"
                        disabled={isDeleting}
                        onClick={() => confirmDelete(department)}
                      >
                        <Trash className="mr-2 h-4 w-4" />
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>

      <div className="flex flex-wrap items-center justify-between gap-3 rounded-md border bg-white px-3 py-2 shadow-sm">
        <div className="text-sm text-muted-foreground">
          Page {meta?.page ?? 1} of {meta?.totalPages ?? 1} · {meta?.totalDocs ?? departments.length} items
        </div>
        <div className="flex items-center gap-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => handlePageChange((meta?.page ?? 1) - 1)}
            disabled={!meta?.hasPrevPage}
          >
            Prev
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => handlePageChange((meta?.page ?? 1) + 1)}
            disabled={!meta?.hasNextPage}
          >
            Next
          </Button>
        </div>
      </div>
    </div>
  )
}

function DepartmentsTableSkeleton() {
  return (
    <div className="rounded-md border">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Name</TableHead>
            <TableHead>Members</TableHead>
            <TableHead>Status</TableHead>
            <TableHead />
          </TableRow>
        </TableHeader>

        <TableBody>
          {Array.from({ length: 5 }).map((_, i) => (
            <TableRow key={i}>
              <TableCell>
                <Skeleton className="h-4 w-40" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-4 w-10" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-5 w-16" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-8 w-8" />
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}
